changeSet.sql:
    create index content_info_expr_idx on sor.content_info ((irtz_type is null)) where (irtz_type is null);
    create index content_resources_resource_type_id_idx on sor.content_resources (resource_type_id);
    create index content_info_id_version_idx on sor.content_info(content_id,content_version_id);
    create index content_resources_id_version_idx on sor.content_resources(content_id,content_version_id);
        create index  decision_id_version on sor.decision(content_id,content_version_id);
create index  content_history_hist_end on sor.content_history(content_id,end_dt);
create index  content_history_end on sor.content_history(end_dt);
create index  content_history_id_version on sor.content_history(content_id,content_version_id);
create index  content_history_id_addon_version on sor.content_history(content_id,addon_version_id);

rollback.sql:
drop index sor.content_info_expr_idx;
drop index sor.content_resources_resource_type_id_idx;
drop index sor.content_info_id_version_idx;
drop index sor.content_resources_id_version_idx;
drop index sor.decision_id_version;
drop index sor.content_history_hist_end;
drop index sor.content_history_end;
drop index sor.content_history_id_version;
drop index sor.content_history_id_addon_version;
